// Correctly sorted categories
// Return unique product categories sorted by count
function solve(categories) {
    let uniqueCategories = new Set(categories.flatMap(category => [category, '']));
    let sortedCategories = [...uniqueCategories].sort((a, b) => categories.filter(c => c === b).length - categories.filter(c => c === a).length);
    return sortedCategories;
}
